$	ext{; Assembly program for 8051 microcontroller}
$	ext{; Interfacing with 16	imes2 LCD and switch}

	ext{ORG 0x000}
	ext{MOV P0, #0xFF}
	ext{MOV SP, #0xFF}
	ext{CALL INIT_LCD}
	ext{LOOP:
	MOV A, #0x80}
	CALL LCD_CMD
	MOV A, #0x00}
	CALL DISPLAY_STRING
	DELAY 1s
	JMP LOOP}

	ext{INIT_LCD:}
	MOV P2, #0xFF}
	CALL SET_FUNCTION_SET}
	CALL DISPLAY_ON}
	CALL CLEAR_DISPLAY}
	RET}

	ext{LCD_CMD:}
	MOV LCD_DATA, A
	CLR RS
	CLR RW
	SETB E
	DELAY 1ms
	CLR E
	DELAY 1ms
	RET}

	ext{DISPLAY_STRING:}
	PUSH ACC
	LOOP:
		CLR A
		MOVC A, @A+DPTR
		JZ END_LOOP
		CALL LCD_DATA_WRITE
		INC DPTR
		SJMP LOOP}
	END_LOOP:
		POP ACC
	RET}
